// Ambil data callback dari Telegram
const callbackData = $json.callback_query.data;

// Pisahkan "approve" / "reject" / "edit" dengan ID-nya
// Contoh: "approve_123" -> action = "approve", draft_id = "123"
const separatorIndex = callbackData.indexOf('_');
const action = callbackData.substring(0, separatorIndex);
const draftId = callbackData.substring(separatorIndex + 1);

// Kirim ke node berikutnya dalam format JSON yang rapi
return [{
  json: {
    action: action,                // "approve", "reject", atau "edit"
    draft_id: draftId,             // ID dari tabel drafts di Supabase
    chat_id: $json.callback_query.message.chat.id,   // ID chat buat edit pesan nanti
    message_id: $json.callback_query.message.message_id // ID pesan asli buat di-edit
  }
}];

const draft = $input.first().json;
const draftId = draft.id;
const rawText = $('Telegram Trigger1').item.json.message.text;

const blocks = rawText
  .split(/\n\s*\n/)
  .map(t => t.trim())
  .filter(t => t.length > 0);

if (blocks.length === 0) {
  throw new Error("Balasan kosong atau format salah.");
}

const chatId = $('Telegram Trigger1').item.json.message.chat.id;
const edits = [];

for (const block of blocks) {
  const match = block.match(/^(\d+)\s*:\s*([\s\S]+)$/);
  if (!match) {
    throw new Error(`Format salah pada blok: "${block.substring(0, 50)}...". Harus diawali "nomor: isi".`);
  }
  const postNumber = parseInt(match[1], 10);
  const content = match[2].trim();
  edits.push({
    draft_id: draftId,
    post_order: postNumber - 1,
    content: content,
    telegram_chat_id: chatId
  });
}

return edits.map(edit => ({ json: edit }));

const posts = $input.all().map(item => item.json).sort((a, b) => a.post_order - b.post_order);
const previewText = posts.map(p => `${p.post_order + 1}. ${p.content}`).join('\n\n');

return [{
  json: {
    preview_text: previewText,
    draft_id: posts[0].draft_id
  }
}];

const draft = $('Get Draft Awaiting Edit').item.json;
const oldPosts = $input.all().map(item => item.json);
const instruksi = $('Telegram Trigger1').item.json.message.text;

const captionLama = oldPosts
  .sort((a, b) => a.post_order - b.post_order)
  .map(p => p.content)
  .join(' ');

return [{
  json: {
    draft_id: draft.id,
    pillar_name: draft.pillar_name,
    angle: draft.angle,
    topic: draft.topic,
    caption_lama: captionLama,
    instruksi_revisi: instruksi
  }
}];

