  .sort((a, b) => a.post_order - b.post_order)
  .map((p, i) => `${i + 1}/${posts.length}\n${p.content}`)
  .join('\n\n---\n\n');

// draft_id dari "Get Draft Awaiting Edit" (pakai .first(), bukan .item)
