const draft = $('Get a row2').item.json;
const posts = $('Get many rows3').all().map(item => item.json);

if (!posts || posts.length === 0) {
  throw new Error(`Draft ${draft.id} tidak memiliki thread_posts. Harap edit terlebih dahulu.`);
}

const threadItems = posts
  .sort((a, b) => a.post_order - b.post_order)
  .map(p => {
    let content = p.content.trim();
    if (content.length > 480) {
      const truncated = content.slice(0, 477);
      const lastPunct = Math.max(
        truncated.lastIndexOf('.'),
        truncated.lastIndexOf('?'),
        truncated.lastIndexOf('!')
      );
      content = lastPunct > 400 ? content.slice(0, lastPunct + 1) : truncated + '...';
    }
    return { content };
  });

return [{
  json: {
    ...draft,
    content: threadItems[0].content,
    threadItems: threadItems.slice(1)   // <- buang item pertama, sisain post ke-2 dst
  }
}];
